<?php $pageTitle='آراء العملاء'; include __DIR__.'/includes/header.php'; $pdo=getDB();
if($_SERVER['REQUEST_METHOD']==='POST' && adminTableExists($pdo,'testimonials')){$pdo->prepare('INSERT INTO testimonials (client_name,company,country,content_ar,content_en,status,sort_order) VALUES (?,?,?,?,?,?,?)')->execute([trim($_POST['client_name']),trim($_POST['company']),trim($_POST['country']),trim($_POST['content_ar']),trim($_POST['content_en']),$_POST['status']??'active',(int)($_POST['sort_order']??0)]);} $items=adminTableExists($pdo,'testimonials')?adminFetchAll($pdo,'SELECT * FROM testimonials ORDER BY sort_order,id DESC'):[];?>
<div class="container-fluid"><h1 class="h4">إدارة آراء العملاء</h1><form method="post" class="card card-body mb-3"><div class="row g-2"><div class="col"><input class="form-control" name="client_name" placeholder="الاسم" required></div><div class="col"><input class="form-control" name="company" placeholder="الشركة"></div><div class="col"><button class="btn btn-primary">إضافة</button></div></div></form><table class="table table-sm table-bordered"><tr><th>#</th><th>العميل</th><th>الشركة</th><th>الحالة</th></tr><?php foreach($items as $i):?><tr><td><?php echo $i['id'];?></td><td><?php echo escape($i['client_name']);?></td><td><?php echo escape($i['company']);?></td><td><?php echo escape($i['status']);?></td></tr><?php endforeach;?></table></div>
<?php include __DIR__.'/includes/footer.php'; ?>
